import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import MasterLayout from './layouts/admin/MasterLayout';

import Dashboard from './assests/admin/admin/Dashboard';
import Profile from './assests/admin/admin/Profile';


function App()
{
  return (
    <div className="App">
      <Router>
        <Routes>
          {/* 2. Define the Parent Route for the admin section */}
          <Route path="/admin" element={<MasterLayout />}>
            {/* 3. Nest Child Routes inside the parent */}
            <Route path="dashboard" element={<Dashboard />} /> {/* 4. Path is relative: /admin/dashboard */}
            <Route path="profile" element={<Profile />} />   {/* 4. Path is relative: /admin/profile */}
          </Route>
        </Routes>
      </Router>
    </div >
  );
}

export default App;
